{"content":"/**
 * robot.js — Parametric humanoid robot manipulator
 * ==================================================
 * 7-DOF serial arm (S-R-S chain) + anthropomorphic 21-DOF five-finger hand.
 * Units: mm. Frame: Z-up, arm base at origin, posed straight up (all joints 0°).
 * Style: collaborative-robot look — white shells, dark grey joint rings.
 *
 * Every DOF is represented as visible joint geometry:
 *   - roll joints  -> cylindrical collars with a seam groove
 *   - pitch joints -> pancake housings with clevis fork + pin bosses
 *   - 2-DOF knuckles -> two stacked orthogonal pin hinges (gimbal)
 *
 * DOF checksum: arm 7 (J1–J7) + hand 21 (4 fingers x 4 + thumb 5) = 28.
 *
 * Exports: defaultParams, buildRobot(params), countDOF(root), disposeRobot(root)
 */

import * as THREE from 'three';
import { RoundedBoxGeometry } from '«HIGH_ENTROPY».js';

/* ============================== PARAMETERS ============================== */

export const defaultParams = {
  /* ---- arm: base ---- */
  base_dia: 160,            // pedestal diameter
  base_height: 110,         // pedestal height (incl. flange)
  base_fillet: 6,           // top edge fillet
  base_flange_dia: 185,     // mounting flange diameter
  base_flange_t: 12,        // mounting flange thickness
  base_bolt_circle: 130,    // M8 bolt circle
  base_bolt_dia: 9,         // M8 clearance hole
  base_neck_dia: 118,       // waisted neck so the bolts stay visible

  /* ---- arm: joints (diameters / widths / heights) ---- */
  j1_dia: 110, j1_h: 80,    // J1 base yaw (roll collar, axis Z)
  j2_dia: 110, j2_w: 90,    // J2 shoulder pitch (pancake, axis Y)
  j3_dia: 85,  j3_h: 60,    // J3 upper-arm roll (inline collar)
  j4_dia: 85,  j4_w: 75,    // J4 elbow pitch (pancake, axis Y)
  j5_dia: 65,  j5_h: 50,    // J5 forearm roll (inline collar)
  j6_dia: 60,  j6_w: 55,    // J6 wrist pitch (pancake, axis Y)
  j7_dia: 55,  j7_h: 45,    // J7 tool roll (collar, axis Z)

  /* ---- arm: links ---- */
  link1_d0: 100, link1_d1: 85, link1_len: 320,  // upper arm taper + length
  link2_d0: 75,  link2_d1: 65, link2_len: 280,  // forearm taper + length
  elbow_offset: 70,                              // lateral +X offset above elbow

  /* ---- tool flange (ISO 9409-1 style) ---- */
  flange_dia: 63, flange_t: 10,
  flange_bolt_circle: 50, flange_bolt_dia: 6.6,  // M6 clearance
  flange_pilot_dia: 31.5,                        // center pilot recess

  /* ---- hand: palm ---- */
  palm_len: 95, palm_w: 85, palm_t: 28, palm_fillet: 8,
  wrist_boss_dia: 50, wrist_boss_h: 20,

  /* ---- hand: fingers (index, middle, ring, little) ---- */
  finger_spacing: 22,
  finger_splay: [0, 3, 6, 9],                    // degrees, outward fan
  finger_scales: { index: 0.95, middle: 1.0, ring: 0.95, little: 0.80 },
  mcp_pin_dia: 16,                               // 2-DOF gimbal knuckle pins
  prox_dia: 18, prox_len: 48,
  pip_pin_dia: 12,
  mid_dia: 15,  mid_len: 28,
  dip_pin_dia: 10,
  dist_dia: 13, dist_len: 24,

  /* ---- hand: thumb ---- */
  thumb_cmc_pin_dia: 18,
  thumb_meta_dia: 19, thumb_meta_len: 45,
  thumb_roll_dia: 17,                            // axial opposition collar
  thumb_mcp_pin_dia: 14, thumb_prox_dia: 16, thumb_prox_len: 35,
  thumb_ip_pin_dia: 11,  thumb_dist_dia: 14, thumb_dist_len: 28,
  thumb_tilt_deg: 45,                            // tilt from vertical (45° base boss)
  thumb_splay_deg: 40,                           // azimuth toward radial side
  thumb_twist_deg: -50,                          // twist so the pad opposes the fingers

  /* ---- common ---- */
  seam_groove_width: 1.5,
  pin_clearance: 0.4,

  /* ---- colors ---- */
  color_shell: 0xf4f5f7,
  color_joint: 0x33363d,
  color_accent: 0x17191d,
  color_pad: 0x3e424a,
};

/* ============================== INTERNALS =============================== */

let MAT = null; // materials for the current build (set in buildRobot)

function makeMaterials(p) {
  return {
    shell:  new THREE.MeshStandardMaterial({ color: p.color_shell,  roughness: 0.38, metalness: 0.05 }),
    joint:  new THREE.MeshStandardMaterial({ color: p.color_joint,  roughness: 0.50, metalness: 0.35 }),
    accent: new THREE.MeshStandardMaterial({ color: p.color_accent, roughness: 0.30, metalness: 0.65 }),
    pad:    new THREE.MeshStandardMaterial({ color: p.color_pad,    roughness: 0.90, metalness: 0.00 }),
  };
}

function mesh(geo, mat) {
  const m = new THREE.Mesh(geo, mat);
  m.castShadow = m.receiveShadow = true;
  return m;
}

/** Cylinder along 'x' | 'y' | 'z', centered at origin. rTop is the +axis end. */
function cylinder(axis, rTop, rBot, h, mat, seg = 48) {
  const g = new THREE.CylinderGeometry(rTop, rBot, h, seg);
  if (axis === 'z') g.rotateX(Math.PI / 2);
  else if (axis === 'x') g.rotateZ(Math.PI / 2);
  return mesh(g, mat);
}

/** Capsule along axis; totalLen includes both hemispherical caps. */
function capsule(axis, r, totalLen, mat) {
  const g = new THREE.CapsuleGeometry(r, Math.max(totalLen - 2 * r, 0.1), 8, 24);
  if (axis === 'z') g.rotateX(Math.PI / 2);
  else if (axis === 'x') g.rotateZ(Math.PI / 2);
  return mesh(g, mat);
}

/** Roll joint: white collar split by a recessed dark seam groove. Axis Z, centered. */
function rollCollar(p, dia, h) {
  const g = new THREE.Group();
  const r = dia / 2, gw = p.seam_groove_width;
  const segH = (h - gw) / 2;
  for (const s of [-1, 1]) {
    const c = cylinder('z', r, r, segH, MAT.shell);
    c.position.z = s * (gw / 2 + segH / 2);
    g.add(c);
  }
  g.add(cylinder('z', r - 1.2, r - 1.2, gw + 6, MAT.joint)); // groove floor
  return g;
}

/**
 * Pitch joint: pancake housing, axis along Y. Dark rotor band, white cheeks,
 * pin bosses with end caps, and a clevis fork (two plates) reaching forkSign*forkLen
 * in Z to grab the neighboring link.
 */
function pitchJoint(p, dia, width, forkLen, forkSign) {
  const g = new THREE.Group();
  const r = dia / 2;
  g.add(cylinder('y', r, r, width * 0.56, MAT.joint)); // rotor band
  for (const s of [-1, 1]) {
    const cheek = cylinder('y', r * 0.97, r * 0.97, width * 0.16, MAT.shell);
    cheek.position.y = s * (width * 0.28 + width * 0.08);
    g.add(cheek);
    const boss = cylinder('y', r * 0.34, r * 0.34, 9, MAT.joint);
    boss.position.y = s * (width / 2 + 2);
    g.add(boss);
    const cap = cylinder('y', r * 0.42 + p.pin_clearance, r * 0.42 + p.pin_clearance, 3.5, MAT.accent);
    cap.position.y = s * (width / 2 + 6.5);
    g.add(cap);
    if (forkLen > 0) {
      const t = Math.max(dia * 0.13, 8);
      const plateLen = forkLen + r * 0.7;
      const plate = mesh(new RoundedBoxGeometry(dia * 0.8, t, plateLen, 3, Math.min(5, t / 2 - 0.5)), MAT.shell);
      plate.position.set(0, s * (width / 2 + t / 2 - 2), forkSign * plateLen / 2);
      g.add(plate);
    }
  }
  return g;
}

/**
 * 1-DOF pin hinge (clevis fork + tongue): white tongue disc in the middle,
 * white fork cheeks outboard, dark pin all the way through with accent end-caps.
 * Dark clearance rings (pin_clearance) show the running fit. Centered at origin.
 */
function pinHinge(p, pinDia, width, axis) {
  const g = new THREE.Group();
  const r = pinDia / 2;
  const ax = axis === 'x' ? new THREE.Vector3(1, 0, 0) : new THREE.Vector3(0, 1, 0);
  const place = (m, d) => { m.position.copy(ax).multiplyScalar(d); return m; };
  g.add(cylinder(axis, r * 1.55, r * 1.55, width * 0.42, MAT.shell)); // tongue
  for (const s of [-1, 1]) {
    g.add(place(cylinder(axis, r + p.pin_clearance + 1.2, r + p.pin_clearance + 1.2, width * 0.07, MAT.accent), s * width * 0.25)); // clearance ring
    g.add(place(cylinder(axis, r * 1.55, r * 1.55, width * 0.16, MAT.shell), s * width * 0.37)); // fork cheek
    g.add(place(cylinder(axis, r * 1.25 + p.pin_clearance, r * 1.25 + p.pin_clearance, 2.5, MAT.accent), s * (width / 2 + 1.3))); // pin end-cap
  }
  g.add(cylinder(axis, r, r, width * 1.04, MAT.accent)); // the pin itself
  return g;
}

/** Tapered link split by an inline roll collar at mid-length. zBot is global. */
function linkWithRollCollar(p, dBot, dTop, len, zBot, collarDia, collarH, jointName) {
  const g = new THREE.Group();
  const dAt = (z) => dBot + (dTop - dBot) * ((z - zBot) / len);
  const segLen = len / 2 - collarH / 2;
  const lo = cylinder('z', dAt(zBot + segLen) / 2, dBot / 2, segLen, MAT.shell);
  lo.position.z = zBot + segLen / 2;
  const hi = cylinder('z', dTop / 2, dAt(zBot + len - segLen) / 2, segLen, MAT.shell);
  hi.position.z = zBot + len - segLen / 2;
  const collar = rollCollar(p, collarDia, collarH);
  collar.position.z = zBot + len / 2;
  collar.userData = { dof: 1, joint: jointName };
  g.add(lo, hi, collar);
  return g;
}

/** Smooth S-curve hull between two points (vertical tangents at both ends). */
function sCurveTube(p0, p3, radius) {
  const dz = (p3.z - p0.z) * 0.55;
  const curve = new THREE.CubicBezierCurve3(
    p0,
    new THREE.Vector3(p0.x, p0.y, p0.z + dz),
    new THREE.Vector3(p3.x, p3.y, p3.z - dz),
    p3,
  );
  return mesh(new THREE.TubeGeometry(curve, 32, radius, 24, false), MAT.shell);
}

/** Disc with bolt holes, extruded +Z from z=0. */
function boltedDisc(outerR, thickness, boltCircleR, holeR, holeCount) {
  const shape = new THREE.Shape();
  shape.absarc(0, 0, outerR, 0, Math.PI * 2, false);
  for (let i = 0; i < holeCount; i++) {
    const a = (i + 0.5) * (Math.PI * 2 / holeCount);
    const hole = new THREE.Path();
    hole.absarc(Math.cos(a) * boltCircleR, Math.sin(a) * boltCircleR, holeR, 0, Math.PI * 2, true);
    shape.holes.push(hole);
  }
  const geo = new THREE.ExtrudeGeometry(shape, { depth: thickness, bevelEnabled: false, curveSegments: 48 });
  return mesh(geo, MAT.shell);
}

/* ------------------------------- ARM ----------------------------------- */

function baseAssembly(p) {
  const g = new THREE.Group();
  const ft = p.base_flange_t;

  // mounting flange with four M8 clearance holes on the bolt circle
  g.add(boltedDisc(p.base_flange_dia / 2, ft, p.base_bolt_circle / 2, p.base_bolt_dia / 2, 4));

  // socket-head bolts sitting in the holes
  for (let i = 0; i < 4; i++) {
    const a = (i + 0.5) * Math.PI / 2;
    const head = cylinder('z', p.base_bolt_dia * 0.72, p.base_bolt_dia * 0.72, 7, MAT.accent);
    head.position.set(Math.cos(a) * p.base_bolt_circle / 2, Math.sin(a) * p.base_bolt_circle / 2, ft + 3);
    g.add(head);
  }

  // pedestal body: waisted neck flaring to base_dia, filleted top edge (lathe)
  const R = p.base_dia / 2, nR = p.base_neck_dia / 2, H = p.base_height, f = p.base_fillet;
  const pts = [
    [nR, ft], [nR, ft + 10],
    [nR + (R - nR) * 0.25, ft + 20], [nR + (R - nR) * 0.7, ft + 32], [R, ft + 42],
    [R, H - f],
  ];
  for (let i = 0; i <= 4; i++) { // top fillet quarter-arc
    const a = (i / 4) * Math.PI / 2;
    pts.push([R - f + f * Math.cos(a), H - f + f * Math.sin(a)]);
  }
  pts.push([0.01, H]);
  const lathe = new THREE.LatheGeometry(pts.map(([x, y]) => new THREE.Vector2(x, y)), 64);
  lathe.rotateX(Math.PI / 2);
  g.add(mesh(lathe, MAT.shell));

  // dark transition ring under the J1 collar
  const ring = cylinder('z', p.j1_dia / 2 + 5, p.j1_dia / 2 + 5, 4, MAT.joint);
  ring.position.z = H + 1;
  g.add(ring);
  return g;
}

function toolFlange(p) {
  const g = new THREE.Group();
  g.add(boltedDisc(p.flange_dia / 2, p.flange_t, p.flange_bolt_circle / 2, p.flange_bolt_dia / 2, 4));
  const pilot = cylinder('z', p.flange_pilot_dia / 2, p.flange_pilot_dia / 2, 2, MAT.joint); // pilot recess
  pilot.position.z = p.flange_t - 0.9;
  g.add(pilot);
  return g;
}

/* ------------------------------- HAND ---------------------------------- */

/** Phalanx: capsule with a flat palmar face strip (+X side). Runs z0 .. z0+len. */
function phalanx(d, len, z0) {
  const g = new THREE.Group();
  const cap = capsule('z', d / 2, len, MAT.shell);
  cap.position.z = z0 + len / 2;
  const flat = mesh(new RoundedBoxGeometry(3, d * 0.5, Math.max(len - d, 6), 2, 1.3), MAT.shell);
  flat.position.set(d / 2 - 1.8, 0, z0 + len / 2);
  g.add(cap, flat);
  return g;
}

/** Flat elliptical fingertip pad on the palmar side. */
function fingertipPad(d, zTip) {
  const pad = cylinder('x', d * 0.34, d * 0.34, 1.8, MAT.pad);
  pad.scale.set(1, 1, 1.8);
  pad.position.set(d / 2 - 1.0, 0, zTip);
  return pad;
}

/**
 * One finger, local frame: points +Z, palmar side +X, origin at the palm edge.
 * MCP = gimbal of two stacked orthogonal pin hinges (X = ab/adduction, Y = flexion).
 */
function buildFinger(p, scale, name) {
  const g = new THREE.Group();
  g.name = `finger_${name}`;
  const k = p.mcp_pin_dia;

  const mount = mesh(new RoundedBoxGeometry(k * 1.1, k * 1.1, 12, 3, 3.5), MAT.shell);
  mount.position.z = 4;
  g.add(mount);

  const hingeAbAd = pinHinge(p, k, k * 1.4, 'x');
  hingeAbAd.position.z = 13;
  hingeAbAd.userData = { dof: 1, joint: `${name}_MCP_abduction` };

  const gimbalBlock = mesh(new RoundedBoxGeometry(k * 0.8, k * 0.8, 12, 3, 3), MAT.shell);
  gimbalBlock.position.z = 20;

  const hingeFlex = pinHinge(p, k, k * 1.5, 'y');
  hingeFlex.position.z = 27;
  hingeFlex.userData = { dof: 1, joint: `${name}_MCP_flexion` };
  g.add(hingeAbAd, gimbalBlock, hingeFlex);

  const z0 = 31;
  g.add(phalanx(p.prox_dia, p.prox_len, z0));

  const zPip = z0 + p.prox_len;
  const pip = pinHinge(p, p.pip_pin_dia, p.prox_dia * 1.05, 'y');
  pip.position.z = zPip;
  pip.userData = { dof: 1, joint: `${name}_PIP` };
  g.add(pip, phalanx(p.mid_dia, p.mid_len, zPip));

  const zDip = zPip + p.mid_len;
  const dip = pinHinge(p, p.dip_pin_dia, p.mid_dia * 1.05, 'y');
  dip.position.z = zDip;
  dip.userData = { dof: 1, joint: `${name}_DIP` };
  g.add(dip, phalanx(p.dist_dia, p.dist_len, zDip));

  g.add(fingertipPad(p.dist_dia, zDip + p.dist_len * 0.62));
  g.scale.setScalar(scale);
  return g;
}

/** Thumb, local frame: points +Z, pad side +X. 5 DOF. */
function buildThumb(p) {
  const g = new THREE.Group();
  g.name = 'thumb';

  const boss = cylinder('z', 13, 13, 18, MAT.shell); // 45° angled base boss
  boss.position.z = 2;
  g.add(boss);

  const hingeAbAd = pinHinge(p, p.thumb_cmc_pin_dia, p.thumb_cmc_pin_dia * 1.4, 'x');
  hingeAbAd.position.z = 16;
  hingeAbAd.userData = { dof: 1, joint: 'thumb_CMC_abduction' };

  const gimbalBlock = mesh(new RoundedBoxGeometry(15, 15, 12, 3, 3.5), MAT.shell);
  gimbalBlock.position.z = 23;

  const hingeFlex = pinHinge(p, p.thumb_cmc_pin_dia, p.thumb_cmc_pin_dia * 1.5, 'y');
  hingeFlex.position.z = 31;
  hingeFlex.userData = { dof: 1, joint: 'thumb_CMC_flexion' };
  g.add(hingeAbAd, gimbalBlock, hingeFlex);

  // metacarpal: two segments interrupted by the axial opposition roll collar
  const z0 = 35;
  const r = p.thumb_meta_dia / 2;
  const collarH = 14;
  const segH = (p.thumb_meta_len - collarH) / 2;

  const lo = cylinder('z', r, r, segH, MAT.shell);
  lo.position.z = z0 + segH / 2;
  const loCap = mesh(new THREE.SphereGeometry(r, 24, 16), MAT.shell);
  loCap.position.z = z0;
  const collar = rollCollar(p, p.thumb_roll_dia, collarH);
  collar.position.z = z0 + p.thumb_meta_len / 2;
  collar.userData = { dof: 1, joint: '«HIGH_ENTROPY»' };
  const hi = cylinder('z', r, r, segH, MAT.shell);
  hi.position.z = z0 + p.thumb_meta_len - segH / 2;
  const hiCap = mesh(new THREE.SphereGeometry(r, 24, 16), MAT.shell);
  hiCap.position.z = z0 + p.thumb_meta_len;
  g.add(lo, loCap, collar, hi, hiCap);

  const zMcp = z0 + p.thumb_meta_len;
  const mcp = pinHinge(p, p.thumb_mcp_pin_dia, p.thumb_prox_dia * 1.05, 'y');
  mcp.position.z = zMcp;
  mcp.userData = { dof: 1, joint: 'thumb_MCP' };
  g.add(mcp, phalanx(p.thumb_prox_dia, p.thumb_prox_len, zMcp));

  const zIp = zMcp + p.thumb_prox_len;
  const ip = pinHinge(p, p.thumb_ip_pin_dia, p.thumb_dist_dia * 1.05, 'y');
  ip.position.z = zIp;
  ip.userData = { dof: 1, joint: 'thumb_IP' };
  g.add(ip, phalanx(p.thumb_dist_dia, p.thumb_dist_len, zIp));

  g.add(fingertipPad(p.thumb_dist_dia, zIp + p.thumb_dist_len * 0.62));
  return g;
}

/** Hand, local frame: origin at tool-flange top center, fingers +Z, palmar +X. */
function buildHand(p) {
  const hand = new THREE.Group();
  hand.name = 'hand';
  const d2r = THREE.MathUtils.degToRad;

  const boss = cylinder('z', p.wrist_boss_dia / 2, p.wrist_boss_dia / 2, p.wrist_boss_h, MAT.shell);
  boss.position.z = p.wrist_boss_h / 2;

  // elliptical neck blending the round boss into the flat palm
  const neck = cylinder('z', p.wrist_boss_dia / 2, p.wrist_boss_dia / 2, 18, MAT.shell);
  neck.scale.set(p.palm_t / p.wrist_boss_dia, 1, 1);
  neck.position.z = p.wrist_boss_h + 9;

  const palmZ0 = p.wrist_boss_h;
  const palmZc = palmZ0 + p.palm_len / 2;
  const palm = mesh(new RoundedBoxGeometry(p.palm_t, p.palm_w, p.palm_len, 4, p.palm_fillet), MAT.shell);
  palm.position.set(0, 0, palmZc);

  // slightly domed dorsal side (-X)
  const dome = mesh(new THREE.SphereGeometry(p.palm_len * 0.42, 32, 16), MAT.shell);
  dome.scale.set(0.22, 0.95, 1.0);
  dome.position.set(-p.palm_t / 2 + 2, 0, palmZc);

  hand.add(boss, neck, palm, dome);

  // four fingers along the top edge, index on the radial (+Y, thumb) side
  const names = ['index', 'middle', 'ring', 'little'];
  const yOff = [1.5, 0.5, -0.5, -1.5];
  names.forEach((n, i) => {
    const f = buildFinger(p, p.finger_scales[n], n);
    f.position.set(2, yOff[i] * p.finger_spacing, palmZ0 + p.palm_len - 3);
    f.rotation.x = d2r(p.finger_splay[i]); // fan toward ulnar side
    hand.add(f);
  });

  // thumb on the palmar-radial corner, on a 45°-angled base boss
  const thumb = buildThumb(p);
  thumb.position.set(p.palm_t / 2 - 4, p.palm_w / 2 - 8, palmZ0 + p.palm_len * 0.2);
  const tilt = d2r(p.thumb_tilt_deg), az = d2r(p.thumb_splay_deg);
  const dir = new THREE.Vector3(
    Math.sin(tilt) * Math.cos(az),
    Math.sin(tilt) * Math.sin(az),
    Math.cos(tilt),
  ).normalize();
  thumb.quaternion.setFromUnitVectors(new THREE.Vector3(0, 0, 1), dir);
  thumb.quaternion.multiply(
    new THREE.Quaternion().setFromAxisAngle(new THREE.Vector3(0, 0, 1), d2r(p.thumb_twist_deg)),
  );
  hand.add(thumb);
  return hand;
}

/* ============================== ASSEMBLY ================================ */

export function buildRobot(params = {}) {
  const p = { ...defaultParams, ...params };
  MAT = makeMaterials(p);

  const robot = new THREE.Group();
  robot.name = '«HIGH_ENTROPY»';

  /* BASE */
  robot.add(baseAssembly(p));
  let z = p.base_height;

  /* J1 — base yaw (axis Z) */
  const j1 = rollCollar(p, p.j1_dia, p.j1_h);
  j1.position.z = z + p.j1_h / 2;
  j1.userData = { dof: 1, joint: 'J1_base_yaw' };
  robot.add(j1);
  z += p.j1_h;

  /* J2 — shoulder pitch (axis Y), with rounded shoulder block */
  const j2z = z + p.j2_dia / 2;
  const block = mesh(new RoundedBoxGeometry(p.j2_dia * 0.86, p.j2_w, 70, 4, 14), MAT.shell);
  block.position.set(0, 0, z + 30);
  const j2 = pitchJoint(p, p.j2_dia, p.j2_w, 48, +1);
  j2.position.z = j2z;
  j2.userData = { dof: 1, joint: 'J2_shoulder_pitch' };
  robot.add(block, j2);

  /* LINK 1 (upper arm) with inline J3 roll collar */
  robot.add(linkWithRollCollar(p, p.link1_d0, p.link1_d1, p.link1_len, j2z, p.j3_dia, p.j3_h, 'J3_upperarm_roll'));
  const link1Top = j2z + p.link1_len;

  /* J4 — elbow pitch (axis Y) with lateral offset above */
  const j4z = link1Top + p.j4_dia / 2;
  const j4 = pitchJoint(p, p.j4_dia, p.j4_w, 44, -1);
  j4.position.z = j4z;
  j4.userData = { dof: 1, joint: 'J4_elbow_pitch' };
  robot.add(j4);

  /* S-curve hull carrying the elbow offset into the forearm */
  const fx = p.elbow_offset;
  const fz0 = j4z + p.j4_dia / 2;
  robot.add(sCurveTube(new THREE.Vector3(0, 0, j4z), new THREE.Vector3(fx, 0, fz0 + 22), 30));

  /* LINK 2 (forearm) with inline J5 roll collar */
  const link2 = linkWithRollCollar(p, p.link2_d0, p.link2_d1, p.link2_len, fz0, p.j5_dia, p.j5_h, 'J5_forearm_roll');
  link2.position.x = fx;
  robot.add(link2);
  const link2Top = fz0 + p.link2_len;

  /* J6 — wrist pitch (axis Y) */
  const j6z = link2Top + p.j6_dia / 2;
  const j6 = pitchJoint(p, p.j6_dia, p.j6_w, 26, +1);
  j6.position.set(fx, 0, j6z);
  j6.userData = { dof: 1, joint: 'J6_wrist_pitch' };
  robot.add(j6);

  /* J7 — tool roll (axis Z) ending in the ISO 9409-1 flange */
  const j7z0 = j6z + p.j6_dia / 2;
  const j7 = rollCollar(p, p.j7_dia, p.j7_h);
  j7.position.set(fx, 0, j7z0 + p.j7_h / 2);
  j7.userData = { dof: 1, joint: 'J7_tool_roll' };
  const flange = toolFlange(p);
  flange.position.set(fx, 0, j7z0 + p.j7_h);
  robot.add(j7, flange);

  /* HAND on the tool flange, fingers up */
  const hand = buildHand(p);
  hand.position.set(fx, 0, j7z0 + p.j7_h + p.flange_t);
  robot.add(hand);

  robot.userData.dof = countDOF(robot);
  robot.userData.params = p;
  return robot;
}

/** Sum of all userData.dof markers — should equal 28 (7 arm + 21 hand). */
export function countDOF(root) {
  let n = 0;
  root.traverse((o) => { if (o.userData && o.userData.dof) n += o.userData.dof; });
  return n;
}

/** Free GPU resources of a built robot (geometries + this build's materials). */
export function disposeRobot(root) {
  const mats = new Set();
  root.traverse((o) => {
    if (o.isMesh) {
      o.geometry.dispose();
      mats.add(o.material);
    }
  });
  mats.forEach((m) => m.dispose());
}
