{"content":"// Node smoke test: builds the robot, checks the DOF checksum and geometry sanity.
import * as THREE from 'three';
import { buildRobot, countDOF } from './robot.js';

const robot = buildRobot();
robot.updateMatrixWorld(true);

let meshes = 0, tris = 0, nan = false;
robot.traverse((o) => {
  if (o.isMesh) {
    meshes++;
    const g = o.geometry;
    tris += (g.index ? g.index.count : g.attributes.position.count) / 3;
    const arr = g.attributes.position.array;
    for (let i = 0; i < arr.length; i++) if (Number.isNaN(arr[i])) { nan = true; break; }
  }
});

const box = new THREE.Box3().setFromObject(robot);
const dof = countDOF(robot);
const joints = [];
robot.traverse((o) => { if (o.userData?.joint) joints.push(o.userData.joint); });

console.log('DOF total :', dof, '(expected 28)');
console.log('joints    :', joints.length, '-', joints.join(', '));
console.log('meshes    :', meshes, ' triangles:', Math.round(tris));
console.log('bbox min  :', box.min.toArray().map((v) => v.toFixed(1)).join(', '));
console.log('bbox max  :', box.max.toArray().map((v) => v.toFixed(1)).join(', '));
console.log('NaN verts :', nan);

if (dof !== 28 || nan || joints.length !== 28) {
  console.error('SMOKE TEST FAILED');
  process.exit(1);
}
console.log('OK ✓');
