// minimal FileReader shim for GLTFExporter under Node
globalThis.FileReader = class {
  readAsArrayBuffer(blob) {
    blob.arrayBuffer().then((buf) => { this.result = buf; this.onloadend?.(); });
  }
  readAsDataURL(blob) {
    blob.arrayBuffer().then((buf) => {
      this.result = 'data:«HIGH_ENTROPY»;base64,' + Buffer.from(buf).toString('base64');
