{"content":"/**
 * robot.js — ROBIOS parametric humanoid robot manipulator (articulated)
 * ======================================================================
 * 7-DOF serial arm (S-R-S chain) + anthropomorphic 21-DOF five-finger hand.
 * Units: mm. Frame: Z-up, arm base at origin, posed straight up (all joints 0°).
 * Style: black body shells, grey joint rings, white ROBIOS engraving.
 *
 * The model is a true kinematic hierarchy: every joint is a named pivot Group
 * (J1..J7, <finger>«HIGH_ENTROPY», «HIGH_ENTROPY»
 * _OPP/_MCP/_IP) whose rotation animates everything distal to it. The pivot
 * map is available at robot.userData.joints.
 *
 * Every DOF is visible joint geometry:
 *   - roll joints  -> cylindrical collars with a seam groove
 *   - pitch joints -> pancake housings with clevis fork + pin bosses
 *   - 2-DOF knuckles -> two stacked orthogonal pin hinges (gimbal)
 *
 * DOF checksum: arm 7 (J1–J7) + hand 21 (4 fingers x 4 + thumb 5) = 28.
 *
 * Exports: defaultParams, buildRobot(params), countDOF(root),
 *          disposeRobot(root), setBrandFont(fontJson)
 */

import * as THREE from 'three';
import { RoundedBoxGeometry } from '«HIGH_ENTROPY».js';
import { FontLoader } from '«HIGH_ENTROPY».js';
import { TextGeometry } from '«HIGH_ENTROPY».js';

/* ============================== PARAMETERS ============================== */

export const defaultParams = {
  /* ---- arm: base ---- */
  base_dia: 160,            // pedestal diameter
  base_height: 110,         // pedestal height (incl. flange)
  base_fillet: 6,           // top edge fillet
  base_flange_dia: 185,     // mounting flange diameter
  base_flange_t: 12,        // mounting flange thickness
  base_bolt_circle: 130,    // M8 bolt circle
  base_bolt_dia: 9,         // M8 clearance hole
  base_neck_dia: 118,       // waisted neck so the bolts stay visible

  /* ---- arm: joints (diameters / widths / heights) ---- */
  j1_dia: 110, j1_h: 80,    // J1 base yaw (roll collar, axis Z)
  j2_dia: 110, j2_w: 90,    // J2 shoulder pitch (pancake, axis Y)
  j3_dia: 85,  j3_h: 60,    // J3 upper-arm roll (inline collar)
  j4_dia: 85,  j4_w: 75,    // J4 elbow pitch (pancake, axis Y)
  j5_dia: 65,  j5_h: 50,    // J5 forearm roll (inline collar)
  j6_dia: 60,  j6_w: 55,    // J6 wrist pitch (pancake, axis Y)
  j7_dia: 55,  j7_h: 45,    // J7 tool roll (collar, axis Z)

  /* ---- arm: links ---- */
  link1_d0: 100, link1_d1: 85, link1_len: 320,  // upper arm taper + length
  link2_d0: 75,  link2_d1: 65, link2_len: 280,  // forearm taper + length
  elbow_offset: 70,                              // lateral +X offset above elbow

  /* ---- tool flange (ISO 9409-1 style) ---- */
  flange_dia: 63, flange_t: 10,
  flange_bolt_circle: 50, flange_bolt_dia: 6.6,  // M6 clearance
  flange_pilot_dia: 31.5,                        // center pilot recess

  /* ---- hand: palm ---- */
  palm_len: 95, palm_w: 85, palm_t: 28, palm_fillet: 8,
  wrist_boss_dia: 50, wrist_boss_h: 20,

  /* ---- hand: fingers (index, middle, ring, little) ---- */
  finger_spacing: 22,
  finger_splay: [0, 3, 6, 9],                    // degrees, outward fan
  finger_scales: { index: 0.95, middle: 1.0, ring: 0.95, little: 0.80 },
  mcp_pin_dia: 16,                               // 2-DOF gimbal knuckle pins
  prox_dia: 18, prox_len: 48,
  pip_pin_dia: 12,
  mid_dia: 15,  mid_len: 28,
  dip_pin_dia: 10,
  dist_dia: 13, dist_len: 24,

  /* ---- hand: thumb ---- */
  thumb_cmc_pin_dia: 18,
  thumb_meta_dia: 19, thumb_meta_len: 45,
  thumb_roll_dia: 17,                            // axial opposition collar
  thumb_mcp_pin_dia: 14, thumb_prox_dia: 16, thumb_prox_len: 35,
  thumb_ip_pin_dia: 11,  thumb_dist_dia: 14, thumb_dist_len: 28,
  thumb_tilt_deg: 45,                            // tilt from vertical (45° base boss)
  thumb_splay_deg: 40,                           // azimuth toward radial side
  thumb_twist_deg: -50,                          // twist so the pad opposes the fingers

  /* ---- common ---- */
  seam_groove_width: 1.5,
  pin_clearance: 0.4,

  /* ---- branding ---- */
  brand_text: 'ROBIOS',

  /* ---- colors (black body, grey rings, steel pins, white engraving) ---- */
  color_shell: 0x16181c,
  color_joint: 0x474c55,
  color_accent: 0x9aa0a8,
  color_pad: 0x23252a,
  color_brand: 0xf2f4f7,
};

/* ============================== INTERNALS =============================== */

let MAT = null;        // materials for the current build (set in buildRobot)
let BRAND_FONT = null; // parsed THREE Font for engraving (set via setBrandFont)

/** Provide the raw typeface.json object (e.g. helvetiker_bold) for engraving. */
export function setBrandFont(fontJson) {
  BRAND_FONT = fontJson ? new FontLoader().parse(fontJson) : null;
}

function makeMaterials(p) {
  return {
    shell:  new THREE.MeshStandardMaterial({ color: p.color_shell,  roughness: 0.42, metalness: 0.18 }),
    joint:  new THREE.MeshStandardMaterial({ color: p.color_joint,  roughness: 0.50, metalness: 0.35 }),
    accent: new THREE.MeshStandardMaterial({ color: p.color_accent, roughness: 0.30, metalness: 0.75 }),
    pad:    new THREE.MeshStandardMaterial({ color: p.color_pad,    roughness: 0.90, metalness: 0.00 }),
    brand:  new THREE.MeshStandardMaterial({ color: p.color_brand,  roughness: 0.55, metalness: 0.05 }),
  };
}

function mesh(geo, mat) {
  const m = new THREE.Mesh(geo, mat);
  m.castShadow = m.receiveShadow = true;
  return m;
}

/** Cylinder along 'x' | 'y' | 'z', centered at origin. rTop is the +axis end. */
function cylinder(axis, rTop, rBot, h, mat, seg = 48) {
  const g = new THREE.CylinderGeometry(rTop, rBot, h, seg);
  if (axis === 'z') g.rotateX(Math.PI / 2);
  else if (axis === 'x') g.rotateZ(Math.PI / 2);
  return mesh(g, mat);
}

/** Capsule along axis; totalLen includes both hemispherical caps. */
function capsule(axis, r, totalLen, mat) {
  const g = new THREE.CapsuleGeometry(r, Math.max(totalLen - 2 * r, 0.1), 8, 24);
  if (axis === 'z') g.rotateX(Math.PI / 2);
  else if (axis === 'x') g.rotateZ(Math.PI / 2);
  return mesh(g, mat);
}

/** Roll joint: dark collar split by a recessed seam groove. Axis Z, centered. */
function rollCollar(p, dia, h) {
  const g = new THREE.Group();
  const r = dia / 2, gw = p.seam_groove_width;
  const segH = (h - gw) / 2;
  for (const s of [-1, 1]) {
    const c = cylinder('z', r, r, segH, MAT.shell);
    c.position.z = s * (gw / 2 + segH / 2);
    g.add(c);
  }
  g.add(cylinder('z', r - 1.2, r - 1.2, gw + 6, MAT.joint)); // groove floor
  return g;
}

/** Pitch joint housing (proximal/static side): rotor band, cheeks, pin bosses. */
function pitchHousing(p, dia, width) {
  const g = new THREE.Group();
  const r = dia / 2;
  g.add(cylinder('y', r, r, width * 0.56, MAT.joint)); // rotor band
  for (const s of [-1, 1]) {
    const cheek = cylinder('y', r * 0.97, r * 0.97, width * 0.16, MAT.shell);
    cheek.position.y = s * (width * 0.28 + width * 0.08);
    g.add(cheek);
    const boss = cylinder('y', r * 0.34, r * 0.34, 9, MAT.joint);
    boss.position.y = s * (width / 2 + 2);
    g.add(boss);
    const cap = cylinder('y', r * 0.42 + p.pin_clearance, r * 0.42 + p.pin_clearance, 3.5, MAT.accent);
    cap.position.y = s * (width / 2 + 6.5);
    g.add(cap);
  }
  return g;
}

/** Clevis fork plates (the rotating side of a pitch joint). */
function pitchFork(p, dia, width, forkLen, forkSign) {
  const g = new THREE.Group();
  const r = dia / 2;
  const t = Math.max(dia * 0.13, 8);
  const plateLen = forkLen + r * 0.7;
  for (const s of [-1, 1]) {
    const plate = mesh(new RoundedBoxGeometry(dia * 0.8, t, plateLen, 3, Math.min(5, t / 2 - 0.5)), MAT.shell);
    plate.position.set(0, s * (width / 2 + t / 2 - 2), forkSign * plateLen / 2);
    g.add(plate);
  }
  return g;
}

/**
 * 1-DOF pin hinge (clevis fork + tongue): tongue disc in the middle, fork
 * cheeks outboard, pin all the way through with accent end-caps. Dark
 * clearance rings (pin_clearance) show the running fit. Centered at origin.
 * All parts are rotationally symmetric about the pin, so the hinge can live
 * inside the rotating pivot group without looking wrong.
 */
function pinHinge(p, pinDia, width, axis) {
  const g = new THREE.Group();
  const r = pinDia / 2;
  const ax = axis === 'x' ? new THREE.Vector3(1, 0, 0) : new THREE.Vector3(0, 1, 0);
  const place = (m, d) => { m.position.copy(ax).multiplyScalar(d); return m; };
  g.add(cylinder(axis, r * 1.55, r * 1.55, width * 0.42, MAT.shell)); // tongue
  for (const s of [-1, 1]) {
    g.add(place(cylinder(axis, r + p.pin_clearance + 1.2, r + p.pin_clearance + 1.2, width * 0.07, MAT.pad), s * width * 0.25)); // clearance ring
    g.add(place(cylinder(axis, r * 1.55, r * 1.55, width * 0.16, MAT.shell), s * width * 0.37)); // fork cheek
    g.add(place(cylinder(axis, r * 1.25 + p.pin_clearance, r * 1.25 + p.pin_clearance, 2.5, MAT.accent), s * (width / 2 + 1.3))); // pin end-cap
  }
  g.add(cylinder(axis, r, r, width * 1.04, MAT.accent)); // the pin itself
  return g;
}

/** Tapered link segment between local z0..z1, given the link's global taper. */
function taperSeg(dAt, gz0, gz1, lz0, lz1) {
  // dAt maps *global* link z -> diameter; segment occupies local z lz0..lz1
  const len = lz1 - lz0;
  const m = cylinder('z', dAt(gz1) / 2, dAt(gz0) / 2, len, MAT.shell);
  m.position.z = lz0 + len / 2;
  return m;
}

/** Smooth S-curve hull between two points (vertical tangents at both ends). */
function sCurveTube(p0, p3, radius) {
  const dz = (p3.z - p0.z) * 0.55;
  const curve = new THREE.CubicBezierCurve3(
    p0,
    new THREE.Vector3(p0.x, p0.y, p0.z + dz),
    new THREE.Vector3(p3.x, p3.y, p3.z - dz),
    p3,
  );
  return mesh(new THREE.TubeGeometry(curve, 32, radius, 24, false), MAT.shell);
}

/** Disc with bolt holes, extruded +Z from z=0. */
function boltedDisc(outerR, thickness, boltCircleR, holeR, holeCount) {
  const shape = new THREE.Shape();
  shape.absarc(0, 0, outerR, 0, Math.PI * 2, false);
  for (let i = 0; i < holeCount; i++) {
    const a = (i + 0.5) * (Math.PI * 2 / holeCount);
    const hole = new THREE.Path();
    hole.absarc(Math.cos(a) * boltCircleR, Math.sin(a) * boltCircleR, holeR, 0, Math.PI * 2, true);
    shape.holes.push(hole);
  }
  const geo = new THREE.ExtrudeGeometry(shape, { depth: thickness, bevelEnabled: false, curveSegments: 48 });
  return mesh(geo, MAT.shell);
}

/* --------------------------- BRAND ENGRAVING --------------------------- */

function brandTextGeo(text, size, depth) {
  if (!BRAND_FONT || !text) return null;
  const g = new TextGeometry(text, {
    font: BRAND_FONT, size, depth, curveSegments: 6, bevelEnabled: false,
  });
  g.computeBoundingBox();
  const bb = g.boundingBox;
  g.translate(-(bb.min.x + bb.max.x) / 2, -(bb.min.y + bb.max.y) / 2, 0);
  return g;
}

/** Text wrapped around a Z-axis cylinder of radius R, centered at azimuth az. */
function brandRing(text, size, R, az = 0) {
  const geo = brandTextGeo(text, size, 1.2);
  if (!geo) return null;
  const pos = geo.attributes.position;
  for (let i = 0; i < pos.count; i++) {
    const x = pos.getX(i), y = pos.getY(i), z = pos.getZ(i);
    const theta = az - x / R;
    const r = R + 0.4 + z;
    pos.setXYZ(i, r * Math.cos(theta), r * Math.sin(theta), y);
  }
  geo.computeVertexNormals();
  return mesh(geo, MAT.brand);
}

/** Vertical text (reads bottom-to-top) on a +X-facing cylindrical link.
 *  radiusAt(localZ) lets the letters follow a tapered link. */
function brandVertical(text, size, radiusAt, zCenter) {
  const geo = brandTextGeo(text, size, 1.0);
  if (!geo) return null;
  const pos = geo.attributes.position;
  for (let i = 0; i < pos.count; i++) {
    const x = pos.getX(i), y = pos.getY(i), z = pos.getZ(i);
    const lz = x + zCenter;
    pos.setXYZ(i, radiusAt(lz) + 0.5 + z, y, lz);
  }
  geo.computeVertexNormals();
  return mesh(geo, MAT.brand);
}

/** Flat text on the dorsal (-X) palm face. */
function brandFlat(text, size, xFace, zCenter) {
  const geo = brandTextGeo(text, size, 1.0);
  if (!geo) return null;
  const pos = geo.attributes.position;
  for (let i = 0; i < pos.count; i++) {
    const x = pos.getX(i), y = pos.getY(i), z = pos.getZ(i);
    pos.setXYZ(i, xFace - z, -x, y + zCenter);
  }
  geo.computeVertexNormals();
  return mesh(geo, MAT.brand);
}

/* ------------------------------- ARM ----------------------------------- */

function baseAssembly(p) {
  const g = new THREE.Group();
  g.name = 'base';
  const ft = p.base_flange_t;

  // mounting flange with four M8 clearance holes on the bolt circle
  g.add(boltedDisc(p.base_flange_dia / 2, ft, p.base_bolt_circle / 2, p.base_bolt_dia / 2, 4));

  // socket-head bolts sitting in the holes
  for (let i = 0; i < 4; i++) {
    const a = (i + 0.5) * Math.PI / 2;
    const head = cylinder('z', p.base_bolt_dia * 0.72, p.base_bolt_dia * 0.72, 7, MAT.accent);
    head.position.set(Math.cos(a) * p.base_bolt_circle / 2, Math.sin(a) * p.base_bolt_circle / 2, ft + 3);
    g.add(head);
  }

  // pedestal body: waisted neck flaring to base_dia, filleted top edge (lathe)
  const R = p.base_dia / 2, nR = p.base_neck_dia / 2, H = p.base_height, f = p.base_fillet;
  const pts = [
    [nR, ft], [nR, ft + 10],
    [nR + (R - nR) * 0.25, ft + 20], [nR + (R - nR) * 0.7, ft + 32], [R, ft + 42],
    [R, H - f],
  ];
  for (let i = 0; i <= 4; i++) { // top fillet quarter-arc
    const a = (i / 4) * Math.PI / 2;
    pts.push([R - f + f * Math.cos(a), H - f + f * Math.sin(a)]);
  }
  pts.push([0.01, H]);
  const lathe = new THREE.LatheGeometry(pts.map(([x, y]) => new THREE.Vector2(x, y)), 64);
  lathe.rotateX(Math.PI / 2);
  g.add(mesh(lathe, MAT.shell));

  // ROBIOS engraving wrapped around the pedestal, front and back
  for (const az of [0, Math.PI]) {
    const t = brandRing(p.brand_text, 24, R, az);
    if (t) { t.position.z = (ft + 42 + H - f) / 2; g.add(t); }
  }

  // dark transition ring under the J1 collar
  const ring = cylinder('z', p.j1_dia / 2 + 5, p.j1_dia / 2 + 5, 4, MAT.joint);
  ring.position.z = H + 1;
  g.add(ring);
  return g;
}

function toolFlange(p) {
  const g = new THREE.Group();
  g.add(boltedDisc(p.flange_dia / 2, p.flange_t, p.flange_bolt_circle / 2, p.flange_bolt_dia / 2, 4));
  const pilot = cylinder('z', p.flange_pilot_dia / 2, p.flange_pilot_dia / 2, 2, MAT.joint); // pilot recess
  pilot.position.z = p.flange_t - 0.9;
  g.add(pilot);
  return g;
}

/* ------------------------------- HAND ---------------------------------- */

/** Phalanx: capsule with a flat palmar face strip (+X side). Runs z0 .. z0+len. */
function phalanx(d, len, z0) {
  const g = new THREE.Group();
  const cap = capsule('z', d / 2, len, MAT.shell);
  cap.position.z = z0 + len / 2;
  const flat = mesh(new RoundedBoxGeometry(3, d * 0.5, Math.max(len - d, 6), 2, 1.3), MAT.shell);
  flat.position.set(d / 2 - 1.8, 0, z0 + len / 2);
  g.add(cap, flat);
  return g;
}

/** Flat elliptical fingertip pad on the palmar side. */
function fingertipPad(d, zTip) {
  const pad = cylinder('x', d * 0.34, d * 0.34, 1.8, MAT.pad);
  pad.scale.set(1, 1, 1.8);
  pad.position.set(d / 2 - 1.0, 0, zTip);
  return pad;
}

/** Make a named joint pivot group. */
function pivot(name, axis) {
  const g = new THREE.Group();
  g.name = name;
  g.userData = { dof: 1, joint: name, axis };
  return g;
}

/**
 * One finger as a kinematic chain, local frame: points +Z, palmar +X.
 * root -> MCP_abd (X) -> MCP_flex (Y) -> PIP (Y) -> DIP (Y)
 */
function buildFinger(p, scale, name, joints) {
  const root = new THREE.Group();
  root.name = `finger_${name}`;
  const k = p.mcp_pin_dia;

  const mount = mesh(new RoundedBoxGeometry(k * 1.1, k * 1.1, 12, 3, 3.5), MAT.shell);
  mount.position.z = 4;
  root.add(mount);

  const mcpA = pivot(`${name}_MCP_abd`, 'x');
  mcpA.position.z = 13;
  mcpA.add(pinHinge(p, k, k * 1.4, 'x'));
  root.add(mcpA);

  const gimbalBlock = mesh(new RoundedBoxGeometry(k * 0.8, k * 0.8, 12, 3, 3), MAT.shell);
  gimbalBlock.position.z = 7;
  mcpA.add(gimbalBlock);

  const mcpF = pivot(`${name}_MCP_flex`, 'y');
  mcpF.position.z = 14;
  mcpF.add(pinHinge(p, k, k * 1.5, 'y'));
  mcpA.add(mcpF);

  const z0 = 4; // proximal phalanx starts just above the flexion hinge
  mcpF.add(phalanx(p.prox_dia, p.prox_len, z0));

  const pip = pivot(`${name}_PIP`, 'y');
  pip.position.z = z0 + p.prox_len;
  pip.add(pinHinge(p, p.pip_pin_dia, p.prox_dia * 1.05, 'y'));
  pip.add(phalanx(p.mid_dia, p.mid_len, 0));
  mcpF.add(pip);

  const dip = pivot(`${name}_DIP`, 'y');
  dip.position.z = p.mid_len;
  dip.add(pinHinge(p, p.dip_pin_dia, p.mid_dia * 1.05, 'y'));
  dip.add(phalanx(p.dist_dia, p.dist_len, 0));
  dip.add(fingertipPad(p.dist_dia, p.dist_len * 0.62));
  pip.add(dip);

  root.scale.setScalar(scale);
  joints[mcpA.name] = mcpA; joints[mcpF.name] = mcpF;
  joints[pip.name] = pip; joints[dip.name] = dip;
  return root;
}

/** Thumb chain: CMC_abd (X) -> CMC_flex (Y) -> OPP (Z roll) -> MCP (Y) -> IP (Y). */
function buildThumb(p, joints) {
  const root = new THREE.Group();
  root.name = 'thumb';

  const boss = cylinder('z', 13, 13, 18, MAT.shell); // 45° angled base boss
  boss.position.z = 2;
  root.add(boss);

  const cmcA = pivot('thumb_CMC_abd', 'x');
  cmcA.position.z = 16;
  cmcA.add(pinHinge(p, p.thumb_cmc_pin_dia, p.thumb_cmc_pin_dia * 1.4, 'x'));
  root.add(cmcA);

  const gimbalBlock = mesh(new RoundedBoxGeometry(15, 15, 12, 3, 3.5), MAT.shell);
  gimbalBlock.position.z = 7;
  cmcA.add(gimbalBlock);

  const cmcF = pivot('thumb_CMC_flex', 'y');
  cmcF.position.z = 15;
  cmcF.add(pinHinge(p, p.thumb_cmc_pin_dia, p.thumb_cmc_pin_dia * 1.5, 'y'));
  cmcA.add(cmcF);

  // lower metacarpal segment up to the opposition roll collar
  const r = p.thumb_meta_dia / 2;
  const collarH = 14;
  const segH = (p.thumb_meta_len - collarH) / 2;
  const z0 = 4;
  const loCap = mesh(new THREE.SphereGeometry(r, 24, 16), MAT.shell);
  loCap.position.z = z0;
  const lo = cylinder('z', r, r, segH, MAT.shell);
  lo.position.z = z0 + segH / 2;
  cmcF.add(loCap, lo);

  const opp = pivot('thumb_OPP', 'z'); // axial opposition roll
  opp.position.z = z0 + segH + collarH / 2;
  opp.add(rollCollar(p, p.thumb_roll_dia, collarH));
  const hi = cylinder('z', r, r, segH, MAT.shell);
  hi.position.z = collarH / 2 + segH / 2;
  const hiCap = mesh(new THREE.SphereGeometry(r, 24, 16), MAT.shell);
  hiCap.position.z = collarH / 2 + segH;
  opp.add(hi, hiCap);
  cmcF.add(opp);

  const mcp = pivot('thumb_MCP', 'y');
  mcp.position.z = collarH / 2 + segH;
  mcp.add(pinHinge(p, p.thumb_mcp_pin_dia, p.thumb_prox_dia * 1.05, 'y'));
  mcp.add(phalanx(p.thumb_prox_dia, p.thumb_prox_len, 0));
  opp.add(mcp);

  const ip = pivot('thumb_IP', 'y');
  ip.position.z = p.thumb_prox_len;
  ip.add(pinHinge(p, p.thumb_ip_pin_dia, p.thumb_dist_dia * 1.05, 'y'));
  ip.add(phalanx(p.thumb_dist_dia, p.thumb_dist_len, 0));
  ip.add(fingertipPad(p.thumb_dist_dia, p.thumb_dist_len * 0.62));
  mcp.add(ip);

  for (const j of [cmcA, cmcF, opp, mcp, ip]) joints[j.name] = j;
  return root;
}

/** Hand, local frame: origin at tool-flange top center, fingers +Z, palmar +X. */
function buildHand(p, joints) {
  const hand = new THREE.Group();
  hand.name = 'hand';
  const d2r = THREE.MathUtils.degToRad;

  const boss = cylinder('z', p.wrist_boss_dia / 2, p.wrist_boss_dia / 2, p.wrist_boss_h, MAT.shell);
  boss.position.z = p.wrist_boss_h / 2;

  // elliptical neck blending the round boss into the flat palm
  const neck = cylinder('z', p.wrist_boss_dia / 2, p.wrist_boss_dia / 2, 18, MAT.shell);
  neck.scale.set(p.palm_t / p.wrist_boss_dia, 1, 1);
  neck.position.z = p.wrist_boss_h + 9;

  const palmZ0 = p.wrist_boss_h;
  const palmZc = palmZ0 + p.palm_len / 2;
  const palm = mesh(new RoundedBoxGeometry(p.palm_t, p.palm_w, p.palm_len, 4, p.palm_fillet), MAT.shell);
  palm.position.set(0, 0, palmZc);

  // slightly domed dorsal side (-X)
  const dome = mesh(new THREE.SphereGeometry(p.palm_len * 0.42, 32, 16), MAT.shell);
  dome.scale.set(0.22, 0.95, 1.0);
  dome.position.set(-p.palm_t / 2 + 2, 0, palmZc);

  hand.add(boss, neck, palm, dome);

  // ROBIOS on the dorsal palm face
  const tag = brandFlat(p.brand_text, 10, -p.palm_t / 2 - 6.5, palmZc);
  if (tag) hand.add(tag);

  // four fingers along the top edge, index on the radial (+Y, thumb) side
  const names = ['index', 'middle', 'ring', 'little'];
  const yOff = [1.5, 0.5, -0.5, -1.5];
  names.forEach((n, i) => {
    const f = buildFinger(p, p.finger_scales[n], n, joints);
    f.position.set(2, yOff[i] * p.finger_spacing, palmZ0 + p.palm_len - 3);
    f.rotation.x = d2r(p.finger_splay[i]); // fan toward ulnar side
    hand.add(f);
  });

  // thumb on the palmar-radial corner, on a 45°-angled base boss
  const thumb = buildThumb(p, joints);
  thumb.position.set(p.palm_t / 2 - 4, p.palm_w / 2 - 8, palmZ0 + p.palm_len * 0.2);
  const tilt = d2r(p.thumb_tilt_deg), az = d2r(p.thumb_splay_deg);
  const dir = new THREE.Vector3(
    Math.sin(tilt) * Math.cos(az),
    Math.sin(tilt) * Math.sin(az),
    Math.cos(tilt),
  ).normalize();
  thumb.quaternion.setFromUnitVectors(new THREE.Vector3(0, 0, 1), dir);
  thumb.quaternion.multiply(
    new THREE.Quaternion().setFromAxisAngle(new THREE.Vector3(0, 0, 1), d2r(p.thumb_twist_deg)),
  );
  hand.add(thumb);
  return hand;
}

/* ============================== ASSEMBLY ================================ */

export function buildRobot(params = {}) {
  const p = { ...defaultParams, ...params };
  MAT = makeMaterials(p);
  const joints = {};

  const robot = new THREE.Group();
  robot.name = 'ROBIOS_manipulator';

  /* BASE (static) */
  robot.add(baseAssembly(p));

  /* J1 — base yaw pivot (axis Z) at the pedestal top */
  const j1 = pivot('J1', 'z');
  j1.position.z = p.base_height;
  robot.add(j1);

  const j1collar = rollCollar(p, p.j1_dia, p.j1_h);
  j1collar.position.z = p.j1_h / 2;
  j1.add(j1collar);

  /* shoulder block + J2 housing ride on J1 (proximal side of J2) */
  const j2LocalZ = p.j1_h + p.j2_dia / 2;
  const block = mesh(new RoundedBoxGeometry(p.j2_dia * 0.86, p.j2_w, 70, 4, 14), MAT.shell);
  block.position.z = p.j1_h + 30;
  const j2housing = pitchHousing(p, p.j2_dia, p.j2_w);
  j2housing.position.z = j2LocalZ;
  j1.add(block, j2housing);

  /* J2 — shoulder pitch pivot (axis Y); fork + lower upper-arm rotate with it */
  const j2 = pivot('J2', 'y');
  j2.position.z = j2LocalZ;
  j1.add(j2);
  j2.add(pitchFork(p, p.j2_dia, p.j2_w, 48, +1));

  // upper-arm taper, in *global-equivalent* z measured from J2 center
  const l1d = (gz) => p.link1_d0 + (p.link1_d1 - p.link1_d0) * (gz / p.link1_len);
  const segLen1 = p.link1_len / 2 - p.j3_h / 2;
  j2.add(taperSeg(l1d, 0, segLen1, 0, segLen1));

  // ROBIOS reading up the front of the upper arm
  const brand1 = brandVertical(p.brand_text, 13, (lz) => l1d(lz) / 2, segLen1 / 2 + 10);
  if (brand1) j2.add(brand1);

  /* J3 — upper-arm roll pivot (axis Z) at mid-link */
  const j3 = pivot('J3', 'z');
  j3.position.z = p.link1_len / 2;
  j2.add(j3);
  j3.add(rollCollar(p, p.j3_dia, p.j3_h));
  j3.add(taperSeg((gz) => l1d(gz + p.link1_len / 2), 0, segLen1, p.j3_h / 2, p.link1_len / 2));

  /* J4 housing (proximal, on the upper arm) + elbow pitch pivot */
  const j4LocalZ = p.link1_len / 2 + p.j4_dia / 2;
  const j4housing = pitchHousing(p, p.j4_dia, p.j4_w);
  j4housing.position.z = j4LocalZ;
  const j4fork = pitchFork(p, p.j4_dia, p.j4_w, 44, -1);
  j4fork.position.z = j4LocalZ;
  j3.add(j4housing, j4fork);

  const j4 = pivot('J4', 'y');
  j4.position.z = j4LocalZ;
  j3.add(j4);

  /* S-curve hull carrying the elbow offset into the forearm (rotates with J4) */
  const fx = p.elbow_offset;
  j4.add(sCurveTube(new THREE.Vector3(0, 0, 0), new THREE.Vector3(fx, 0, p.j4_dia / 2 + 22), 30));

  // forearm taper, global-equivalent z measured from forearm bottom
  const l2d = (gz) => p.link2_d0 + (p.link2_d1 - p.link2_d0) * (gz / p.link2_len);
  const segLen2 = p.link2_len / 2 - p.j5_h / 2;
  const fore0 = p.j4_dia / 2; // forearm bottom in J4-local z
  const lowerFore = taperSeg(l2d, 0, segLen2, fore0, fore0 + segLen2);
  lowerFore.position.x = fx;
  j4.add(lowerFore);

  /* J5 — forearm roll pivot (axis Z) at mid-forearm */
  const j5 = pivot('J5', 'z');
  j5.position.set(fx, 0, fore0 + p.link2_len / 2);
  j4.add(j5);
  j5.add(rollCollar(p, p.j5_dia, p.j5_h));
  j5.add(taperSeg((gz) => l2d(gz + p.link2_len / 2), 0, segLen2, p.j5_h / 2, p.link2_len / 2));

  // ROBIOS reading up the front of the forearm
  const brand2 = brandVertical(p.brand_text, 9, (lz) => l2d(lz + p.link2_len / 2) / 2, p.j5_h / 2 + segLen2 / 2);
  if (brand2) j5.add(brand2);

  /* J6 housing (proximal, on the forearm) + wrist pitch pivot */
  const j6LocalZ = p.link2_len / 2 + p.j6_dia / 2;
  const j6housing = pitchHousing(p, p.j6_dia, p.j6_w);
  j6housing.position.z = j6LocalZ;
  j5.add(j6housing);

  const j6 = pivot('J6', 'y');
  j6.position.z = j6LocalZ;
  j5.add(j6);
  j6.add(pitchFork(p, p.j6_dia, p.j6_w, 26, +1));

  /* J7 — tool roll pivot (axis Z): collar, ISO flange, hand */
  const j7 = pivot('J7', 'z');
  j7.position.z = p.j6_dia / 2 + p.j7_h / 2;
  j6.add(j7);
  j7.add(rollCollar(p, p.j7_dia, p.j7_h));

  const flange = toolFlange(p);
  flange.position.z = p.j7_h / 2;
  j7.add(flange);

  const hand = buildHand(p, joints);
  hand.position.z = p.j7_h / 2 + p.flange_t;
  j7.add(hand);

  for (const j of [j1, j2, j3, j4, j5, j6, j7]) joints[j.name] = j;

  robot.userData.joints = joints;
  robot.userData.dofTotal = countDOF(robot);
  robot.userData.params = p;
  return robot;
}

/** Sum of all userData.dof markers — should equal 28 (7 arm + 21 hand). */
export function countDOF(root) {
  let n = 0;
  root.traverse((o) => { if (o.userData && o.userData.dof) n += o.userData.dof; });
  return n;
}

/** Free GPU resources of a built group (geometries + materials). */
export function disposeRobot(root) {
  const mats = new Set();
  root.traverse((o) => {
    if (o.isMesh) {
      o.geometry.dispose();
      mats.add(o.material);
    }
  });
  mats.forEach((m) => m.dispose());
}
