{"content":"/**
 * anim.js — ROBIOS pipetting animation + lab props
 * =================================================
 * Builds the lab scene (beaker, 24-well plate, pipette, liquids, droplet),
 * solves the arm pose with closed-form IK, and bakes the whole pipetting
 * cycle into a standard THREE.AnimationClip ("pipetting"):
 *
 *   home -> reach -> hover beaker -> dip -> aspirate (liquid rises in the
 *   tip, beaker level drops, plunger releases) -> swing to the well plate
 *   -> dispense into two wells (droplets fall, wells fill) -> return home.
 *
 * Because everything is keyframe tracks on named nodes, the clip survives
 * GLB export (GLTFExporter) and plays anywhere: three.js AnimationMixer,
 * <model-viewer autoplay>, Blender, Unity...
 *
 * Exports: LAB, buildLabProps, buildPipette, attachPipette, applyGrip,
 *          solveArmIK, buildPipettingClip
 */

import * as THREE from 'three';
import { RoundedBoxGeometry } from '«HIGH_ENTROPY».js';

const d2r = THREE.MathUtils.degToRad;

/* ------------------------- lab scene layout (mm) ------------------------ */

export const LAB = {
  mat:    { x: 445, y: 0, w: 700, d: 420, h: 8 },
  beaker: { x: 430, y: -190, r: 55, h: 130, liquid: 95 },
  plate:  { x: 430, y: 190, L: 127.8, W: 85.5, H: 16, cols: 6, rows: 4, pitch: 18, wellR: 6.5 },
  targetWells: [[2, 1], [3, 1]],          // [col,row] of the two wells we fill
  pipette: { x_off: 34, z_tip: -10, bodyR: 11 }, // grip offset + tip below flange
  duration: 13,                            // seconds, loops seamlessly
  fps: 20,                                 // bake rate
};

export function wellPos(c, r) {
  const P = LAB.plate;
  return {
    x: P.x - ((P.cols - 1) / 2) * P.pitch + c * P.pitch,
    y: P.y - ((P.rows - 1) / 2) * P.pitch + r * P.pitch,
    zTop: LAB.mat.h + P.H,
  };
}

/* ------------------------------ materials ------------------------------- */

function propMaterials() {
  return {
    glass:  new THREE.MeshStandardMaterial({ color: 0xdfe8ee, roughness: 0.1, metalness: 0, transparent: true, opacity: 0.25, side: THREE.DoubleSide }),
    liquid: new THREE.MeshStandardMaterial({ color: 0x35c4dd, roughness: 0.15, metalness: 0, transparent: true, opacity: 0.85 }),
    body:   new THREE.MeshStandardMaterial({ color: 0xe9ecf1, roughness: 0.45, metalness: 0.05 }),
    blue:   new THREE.MeshStandardMaterial({ color: 0x2f81f7, roughness: 0.4, metalness: 0.1 }),
    dark:   new THREE.MeshStandardMaterial({ color: 0x2b2e34, roughness: 0.8, metalness: 0.1 }),
    well:   new THREE.MeshStandardMaterial({ color: 0x16181c, roughness: 0.6, metalness: 0 }),
  };
}

function mesh(geo, mat) {
  const m = new THREE.Mesh(geo, mat);
  m.castShadow = m.receiveShadow = true;
  return m;
}

/** Z-axis cylinder whose geometry starts at z=0 (so scale.z grows upward). */
function bottomCyl(rTop, rBot, h, mat, seg = 32) {
  const g = new THREE.CylinderGeometry(rTop, rBot, h, seg);
  g.rotateX(Math.PI / 2);
  g.translate(0, 0, h / 2);
  return mesh(g, mat);
}

/* ------------------------------- props ---------------------------------- */

/** Static lab props + animated liquid/droplet nodes. Add to the scene root. */
export function buildLabProps() {
  const M = propMaterials();
  const g = new THREE.Group();
  g.name = 'lab_props';

  // dark lab mat under everything
  const mat = mesh(new RoundedBoxGeometry(LAB.mat.w, LAB.mat.d, LAB.mat.h, 2, 3), M.dark);
  mat.position.set(LAB.mat.x, LAB.mat.y, LAB.mat.h / 2);
  g.add(mat);

  /* beaker (open glass cylinder + liquid) */
  const B = LAB.beaker, bz = LAB.mat.h;
  const wall = new THREE.CylinderGeometry(B.r, B.r, B.h, 48, 1, true);
  wall.rotateX(Math.PI / 2);
  const beaker = mesh(wall, M.glass);
  beaker.name = 'beaker';
  beaker.position.set(B.x, B.y, bz + B.h / 2);
  const bottom = mesh(new THREE.CircleGeometry(B.r, 48), M.glass);
  bottom.position.set(B.x, B.y, bz + 0.5);
  const rim = mesh(new THREE.TorusGeometry(B.r, 1.6, 8, 48), M.glass);
  rim.position.set(B.x, B.y, bz + B.h);
  const bliq = bottomCyl(B.r - 3, B.r - 3, B.liquid, M.liquid, 48);
  bliq.name = 'beaker_liquid';
  bliq.position.set(B.x, B.y, bz + 1);
  g.add(beaker, bottom, rim, bliq);

  /* 24-well plate */
  const P = LAB.plate, pz = LAB.mat.h;
  const body = mesh(new RoundedBoxGeometry(P.L, P.W, P.H, 3, 3), M.body);
  body.name = 'well_plate';
  body.position.set(P.x, P.y, pz + P.H / 2);
  g.add(body);
  for (let c = 0; c < P.cols; c++) {
    for (let r = 0; r < P.rows; r++) {
      const w = wellPos(c, r);
      const hole = mesh(new THREE.CylinderGeometry(P.wellR, P.wellR, 1.2, 24).rotateX(Math.PI / 2), M.well);
      hole.position.set(w.x, w.y, w.zTop + 0.3);
      g.add(hole);
    }
  }
  // animated fills for the two target wells
  LAB.targetWells.forEach(([c, r], i) => {
    const w = wellPos(c, r);
    const fill = mesh(new THREE.CylinderGeometry(P.wellR - 0.7, P.wellR - 0.7, 2.4, 24).rotateX(Math.PI / 2), M.liquid);
    fill.name = `well_fill_${i}`;
    fill.position.set(w.x, w.y, w.zTop + 1.0);
    fill.scale.setScalar(0.001);
    g.add(fill);
  });

  /* falling droplet (reused for both dispenses) */
  const droplet = mesh(new THREE.SphereGeometry(3.6, 16, 12), M.liquid);
  droplet.name = 'droplet';
  droplet.scale.setScalar(0.001);
  droplet.position.set(P.x, P.y, 100);
  g.add(droplet);

  return g;
}

/** Micropipette, local frame: tip at origin, +Z up the barrel. */
export function buildPipette() {
  const M = propMaterials();
  const g = new THREE.Group();
  g.name = 'pipette';

  const tipMarker = new THREE.Object3D();
  tipMarker.name = 'pipette_tip';
  g.add(tipMarker);

  const cone = mesh(new THREE.CylinderGeometry(6, 1.5, 60, 24).rotateX(Math.PI / 2), M.glass);
  cone.position.z = 30;
  const liquid = bottomCyl(4.6, 1.1, 54, propMaterials().liquid, 24);
  liquid.name = 'pipette_liquid';
  liquid.position.z = 1;
  liquid.scale.set(1, 1, 0.001);
  const ejector = mesh(new THREE.CylinderGeometry(8.5, 8.5, 22, 24).rotateX(Math.PI / 2), M.blue);
  ejector.position.z = 71;
  const body = mesh(new THREE.CylinderGeometry(LAB.pipette.bodyR, LAB.pipette.bodyR, 130, 24).rotateX(Math.PI / 2), M.body);
  body.position.z = 125;
  const band = mesh(new THREE.CylinderGeometry(LAB.pipette.bodyR + 0.4, LAB.pipette.bodyR + 0.4, 9, 24).rotateX(Math.PI / 2), M.blue);
  band.position.z = 100;

  const plunger = new THREE.Group();
  plunger.name = 'pipette_plunger';
  const stem = mesh(new THREE.CylinderGeometry(3.5, 3.5, 18, 16).rotateX(Math.PI / 2), M.body);
  stem.position.z = 196;
  const button = mesh(new THREE.CylinderGeometry(7, 7, 9, 24).rotateX(Math.PI / 2), M.blue);
  button.position.z = 208;
  plunger.add(stem, button);

  g.add(cone, liquid, ejector, body, band, plunger);
  return g;
}

/** Mount the pipette in the hand (palmar side, tip below the flange). */
export function attachPipette(robot, pipette) {
  const hand = robot.getObjectByName('hand');
  pipette.position.set(LAB.pipette.x_off, 0, LAB.pipette.z_tip);
  hand.add(pipette);
  return pipette;
}

/** Curl the fingers and thumb around the pipette barrel (static pose). */
export function applyGrip(robot, grip = {}) {
  const G = { mcp: 50, pip: 55, dip: 25, thumb_cmc: 28, thumb_mcp: 25, thumb_ip: 32, ...grip };
  const J = robot.userData.joints;
  for (const f of ['index', 'middle', 'ring', 'little']) {
    J[`${f}_MCP_flex`].rotation.y = d2r(G.mcp);
    J[`${f}_PIP`].rotation.y = d2r(G.pip);
    J[`${f}_DIP`].rotation.y = d2r(G.dip);
  }
  J.thumb_CMC_flex.rotation.y = d2r(G.thumb_cmc);
  J.thumb_MCP.rotation.y = d2r(G.thumb_mcp);
  J.thumb_IP.rotation.y = d2r(G.thumb_ip);
}

/* --------------------------------- IK ----------------------------------- */

/**
 * Closed-form IK for the pipette tip at world (x, y, z), tip pointing
 * straight down. Planar 2-link solution (elbow-back) in the yaw plane,
 * accounting for the lateral elbow offset and the pipette grip offset.
 * Returns joint angles { J1, J2, J4, J6 } in radians.
 */
export function solveArmIK(p, x, y, z) {
  const xOff = LAB.pipette.x_off;
  // tip height above J6 center at zero pose -> below it when inverted
  const dTip = p.j6_dia / 2 + p.j7_h + p.flange_t + LAB.pipette.z_tip;

  const J1 = Math.atan2(y, x);
  const rho6 = Math.hypot(x, y) + xOff;   // palmar (+X) faces -rho when folded
  const h6 = z + dTip;

  const S = p.base_height + p.j1_h + p.j2_dia / 2;          // shoulder height
  const l1 = p.link1_len + p.j4_dia / 2;                    // J2 -> J4
  const Lz = p.j4_dia / 2 + p.link2_len + p.j6_dia / 2;     // J4 -> J6 vertical
  const l2 = Math.hypot(p.elbow_offset, Lz);
  const delta = Math.atan2(p.elbow_offset, Lz);

  const dr = rho6, dh = h6 - S;
  const d = Math.hypot(dr, dh);
  const clamp = (v) => Math.min(1, Math.max(-1, v));
  const alpha = Math.atan2(dr, dh);
  const A = Math.acos(clamp((l1 * l1 + d * d - l2 * l2) / (2 * l1 * d)));
  const B = Math.acos(clamp((l1 * l1 + l2 * l2 - d * d) / (2 * l1 * l2)));

  const phi1 = alpha - A;               // upper-arm angle from vertical
  const phi2 = phi1 + (Math.PI - B);    // J4->J6 line angle from vertical

  const J2 = phi1;
  const J4 = phi2 - phi1 - delta;
  const J6 = Math.PI - (J2 + J4);       // tool axis points straight down
  return { J1, J2, J4, J6 };
}

/** Apply an IK pose (or any subset of joint angles) to the robot. */
export function applyArmPose(robot, pose) {
  const J = robot.userData.joints;
  if ('J1' in pose) J.J1.rotation.z = pose.J1;
  if ('J2' in pose) J.J2.rotation.y = pose.J2;
  if ('J4' in pose) J.J4.rotation.y = pose.J4;
  if ('J6' in pose) J.J6.rotation.y = pose.J6;
}

/* ------------------------------ timeline -------------------------------- */

const smooth = (u) => u * u * u * (u * (u * 6 - 15) + 10); // smootherstep

function lerpPose(a, b, u) {
  const s = smooth(Math.min(1, Math.max(0, u)));
  const out = {};
  for (const k of ['J1', 'J2', 'J4', 'J6']) out[k] = a[k] + (b[k] - a[k]) * s;
  return out;
}

/** Piecewise-linear channel: [[t, value], ...] -> value(t). */
function channel(keys) {
  return (t) => {
    if (t <= keys[0][0]) return keys[0][1];
    for (let i = 1; i < keys.length; i++) {
      if (t <= keys[i][0]) {
        const [t0, v0] = keys[i - 1], [t1, v1] = keys[i];
        return v0 + (v1 - v0) * smooth((t - t0) / (t1 - t0));
      }
    }
    return keys[keys.length - 1][1];
  };
}

/**
 * Bake the full pipetting cycle into an AnimationClip bound by node name.
 * Track targets: J1/J2/J4/J6 quaternions, pipette_liquid / beaker_liquid /
 * well_fill_0 / well_fill_1 scales, droplet position+scale, plunger position.
 */
export function buildPipettingClip(p) {
  const B = LAB.beaker;
  const w0 = wellPos(...LAB.targetWells[0]);
  const w1 = wellPos(...LAB.targetWells[1]);
  const bTop = LAB.mat.h + B.h;
  const dipZ = LAB.mat.h + 55;            // tip below the liquid surface
  const dispZ = w0.zTop + 18;             // tip hover above the well

  const ik = (x, y, z) => solveArmIK(p, x, y, z);
  const HOME = { J1: 0, J2: 0, J4: 0, J6: 0 };
  const READY = ik(380, 0, 330);
  const BHOV = ik(B.x, B.y, bTop + 70);
  const BDIP = ik(B.x, B.y, dipZ);
  const PHOV0 = ik(w0.x, w0.y, dispZ + 70);
  const PD0 = ik(w0.x, w0.y, dispZ);
  const PHOV1 = ik(w1.x, w1.y, dispZ + 70);
  const PD1 = ik(w1.x, w1.y, dispZ);

  // [t0, t1, fromPose, toPose] — gaps between segments hold the last pose
  const segs = [
    [0.0, 0.4, HOME, HOME],
    [0.4, 2.0, HOME, READY],
    [2.0, 3.1, READY, BHOV],
    [3.1, 3.9, BHOV, BDIP],
    [3.9, 5.1, BDIP, BDIP],     // aspirate
    [5.1, 5.9, BDIP, BHOV],
    [5.9, 7.3, BHOV, PHOV0],    // swing across to the plate
    [7.3, 7.9, PHOV0, PD0],
    [7.9, 8.7, PD0, PD0],       // dispense into well 0
    [8.7, 9.2, PD0, PHOV0],
    [9.2, 9.8, PHOV0, PD1],
    [9.8, 10.6, PD1, PD1],      // dispense into well 1
    [10.6, 11.1, PD1, PHOV1],
    [11.1, 13.0, PHOV1, HOME],
  ];
  const poseAt = (t) => {
    for (const [t0, t1, a, b] of segs) {
      if (t <= t1) return lerpPose(a, b, (t - t0) / (t1 - t0));
    }
    return HOME;
  };

  /* FX channels */
  const tipLiquid = channel([[3.9, 0.001], [5.05, 1], [7.95, 1], [8.6, 0.55], [9.85, 0.55], [10.5, 0.02]]);
  const beakerLvl = channel([[3.95, 1], [5.1, 0.95]]);
  const fill0 = channel([[7.95, 0.001], [8.6, 1]]);
  const fill1 = channel([[9.85, 0.001], [10.5, 1]]);
  const plunger = channel([
    [2.6, 0], [3.0, -6],          // pre-press on approach
    [3.95, -6], [5.05, 0],        // release = aspirate
    [7.85, 0], [8.1, -6],         // dispense 1
    [8.9, -6], [9.1, 0],
    [9.85, 0], [10.1, -6],        // dispense 2
    [11.0, -6], [11.4, 0],
  ]);

  // droplet bursts: form at the tip, fall to the well, vanish on impact
  const bursts = [
    { t0: 8.05, well: w0 },
    { t0: 9.95, well: w1 },
  ];
  function dropletAt(t) {
    for (const { t0, well } of bursts) {
      const zStart = dispZ - 4;
      if (t >= t0 && t <= t0 + 0.62) {
        const u = t - t0;
        if (u < 0.22) return { s: 0.2 + (u / 0.22) * 0.8, x: well.x, y: well.y, z: zStart };
        const v = (u - 0.22) / 0.34;                       // fall (eased-in)
        if (v <= 1) return { s: 1, x: well.x, y: well.y, z: zStart - (zStart - well.zTop - 2) * v * v };
        return { s: 0.001, x: well.x, y: well.y, z: well.zTop + 2 };
      }
    }
    return { s: 0.001, x: w0.x, y: w0.y, z: 60 };
  }

  /* sample everything uniformly */
  const n = Math.round(LAB.duration * LAB.fps) + 1;
  const times = new Float32Array(n);
  const q = { J1: [], J2: [], J4: [], J6: [] };
  const sTip = [], sBeaker = [], sF0 = [], sF1 = [], pPl = [], pDr = [], sDr = [];
  const quat = new THREE.Quaternion();
  const AX = { J1: new THREE.Vector3(0, 0, 1), J2: new THREE.Vector3(0, 1, 0), J4: new THREE.Vector3(0, 1, 0), J6: new THREE.Vector3(0, 1, 0) };

  for (let i = 0; i < n; i++) {
    const t = i / LAB.fps;
    times[i] = t;
    const pose = poseAt(t);
    for (const j of ['J1', 'J2', 'J4', 'J6']) {
      quat.setFromAxisAngle(AX[j], pose[j]);
      q[j].push(quat.x, quat.y, quat.z, quat.w);
    }
    sTip.push(1, 1, tipLiquid(t));
    sBeaker.push(1, 1, beakerLvl(t));
    const f0 = fill0(t), f1 = fill1(t);
    sF0.push(f0, f0, f0);
    sF1.push(f1, f1, f1);
    pPl.push(0, 0, plunger(t));
    const dr = dropletAt(t);
    pDr.push(dr.x, dr.y, dr.z);
    sDr.push(dr.s, dr.s, dr.s);
  }

  const tracks = [
    new THREE.QuaternionKeyframeTrack('J1.quaternion', times, q.J1),
    new THREE.QuaternionKeyframeTrack('J2.quaternion', times, q.J2),
    new THREE.QuaternionKeyframeTrack('J4.quaternion', times, q.J4),
    new THREE.QuaternionKeyframeTrack('J6.quaternion', times, q.J6),
    new THREE.VectorKeyframeTrack('pipette_liquid.scale', times, sTip),
    new THREE.VectorKeyframeTrack('beaker_liquid.scale', times, sBeaker),
    new THREE.VectorKeyframeTrack('well_fill_0.scale', times, sF0),
    new THREE.VectorKeyframeTrack('well_fill_1.scale', times, sF1),
    new THREE.VectorKeyframeTrack('pipette_plunger.position', times, pPl),
    new THREE.VectorKeyframeTrack('droplet.position', times, pDr),
    new THREE.VectorKeyframeTrack('droplet.scale', times, sDr),
  ];
  return new THREE.AnimationClip('pipetting', LAB.duration, tracks);
}

/**
 * One-call setup: builds props + pipette, mounts and grips the pipette,
 * and returns everything needed to play or export the animation.
 * `stage` (the returned group) contains the robot and all props.
 */
export function setupPipettingStage(robot, p) {
  const stage = new THREE.Group();
  stage.name = 'ROBIOS_stage';
  const props = buildLabProps();
  const pipette = buildPipette();
  attachPipette(robot, pipette);
  applyGrip(robot);
  stage.add(robot, props);
  const clip = buildPipettingClip(p);
  return { stage, props, pipette, clip };
}
