{"content":"// Node smoke test: DOF checksum, geometry sanity, IK-vs-FK accuracy, clip bake.
import * as THREE from 'three';
import { readFile } from 'node:fs/promises';
import { buildRobot, countDOF, defaultParams, setBrandFont } from './robot.js';
import { setupPipettingStage, solveArmIK, applyArmPose, LAB, wellPos } from './anim.js';

const fontJson = JSON.parse(await readFile(
  new URL('.«HIGH_ENTROPY».typeface.json', import.meta.url), 'utf8'));
setBrandFont(fontJson);

const p = { ...defaultParams };
const robot = buildRobot(p);
const { stage, clip } = setupPipettingStage(robot, p);
stage.updateMatrixWorld(true);

/* --- DOF + geometry --- */
let meshes = 0, tris = 0, nan = false;
stage.traverse((o) => {
  if (o.isMesh) {
    meshes++;
    const g = o.geometry;
    tris += (g.index ? g.index.count : g.attributes.position.count) / 3;
    const arr = g.attributes.position.array;
    for (let i = 0; i < arr.length; i++) if (Number.isNaN(arr[i])) { nan = true; break; }
  }
});
const dof = countDOF(robot);
console.log('DOF total :', dof, '(expected 28) | meshes:', meshes, '| tris:', Math.round(tris), '| NaN:', nan);

/* --- IK vs FK through the real scene graph --- */
const tipMarker = robot.getObjectByName('pipette_tip');
const targets = [
  [LAB.beaker.x, LAB.beaker.y, LAB.mat.h + 55],
  [wellPos(2, 1).x, wellPos(2, 1).y, wellPos(2, 1).zTop + 18],
  [380, 0, 330],
];
let maxErr = 0;
for (const [x, y, z] of targets) {
  applyArmPose(robot, solveArmIK(p, x, y, z));
  stage.updateMatrixWorld(true);
  const w = tipMarker.getWorldPosition(new THREE.Vector3());
  const err = w.distanceTo(new THREE.Vector3(x, y, z));
  maxErr = Math.max(maxErr, err);
  console.log(`IK tip (${x.toFixed(0)}, ${y.toFixed(0)}, ${z.toFixed(0)}) -> FK (${w.x.toFixed(1)}, ${w.y.toFixed(1)}, ${w.z.toFixed(1)})  err ${err.toFixed(2)} mm`);
}

/* --- clip sanity --- */
console.log('clip      :', clip.name, clip.duration + 's,', clip.tracks.length, 'tracks');
const names = clip.tracks.map((t) => t.name);

const ok = dof === 28 && !nan && maxErr < 2.0 && clip.tracks.length === 11 &&
  names.includes('J2.quaternion') && names.includes('droplet.position');
if (!ok) { console.error('SMOKE TEST FAILED'); process.exit(1); }
console.log('OK ✓');
