<script type="module">
import * as THREE from 'three';
import { OrbitControls } from '«HIGH_ENTROPY».js';
import { GLTFExporter } from '«HIGH_ENTROPY».js';
import { RoomEnvironment } from '«HIGH_ENTROPY».js';
import GUI from 'https://cdn.jsdelivr.net/npm/lil-gui@0.20/+esm';
import { buildRobot, defaultParams, countDOF, disposeRobot, setBrandFont } from './robot.js';
import { setupPipettingStage } from './anim.js';

const errEl = document.getElementById('err');
window.addEventListener('error', (e) => {
  errEl.style.display = 'block';
  errEl.textContent = 'Error: ' + e.message;
});

const q = new URLSearchParams(location.search);
const isShot = q.get('shot') === '1';
const freezeT = q.has('t') ? parseFloat(q.get('t')) : null;

/* brand font for the ROBIOS engraving */
setBrandFont(await (await fetch(
  'https://cdn.jsdelivr.net/npm/three@0.169.«HIGH_ENTROPY».typeface.json')).json());

/* ---------- renderer / scene (Z-up, mm) ---------- */
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.setSize(innerWidth, innerHeight);
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
document.getElementById('app').appendChild(renderer.domElement);

const scene = new THREE.Scene();
scene.background = new THREE.Color(0xe9ebf0);
const pmrem = new THREE.PMREMGenerator(renderer);
scene.environment = pmrem.fromScene(new RoomEnvironment(), 0.04).texture;
scene.environmentIntensity = 0.85;

const camera = new THREE.PerspectiveCamera(40, innerWidth / innerHeight, 1, 20000);
camera.up.set(0, 0, 1);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;

if (q.get('view') === 'hand') {
  camera.position.set(560, -460, 1330);
  controls.target.set(70, 0, 1120);
} else if (q.get('view') === 'lab') {
  camera.position.set(1150, -650, 520);
  controls.target.set(380, 0, 220);
} else {
  camera.position.set(1680, -1480, 1020);
  controls.target.set(220, 0, 520);
}

const sun = new THREE.DirectionalLight(0xffffff, 2.0);
sun.position.set(700, -500, 1400);
sun.castShadow = true;
sun.shadow.mapSize.set(2048, 2048);
sun.shadow.camera.left = sun.shadow.camera.bottom = -1200;
sun.shadow.camera.right = sun.shadow.camera.top = 1200;
sun.shadow.camera.near = 1;
sun.shadow.camera.far = 5000;
sun.shadow.bias = -0.0004;
scene.add(sun, new THREE.HemisphereLight(0xdfe6ee, 0x8a8f99, 0.5));

const ground = new THREE.Mesh(
  new THREE.CircleGeometry(1600, 64),
  new THREE.MeshStandardMaterial({ color: 0xd6d9de, roughness: 0.95 }),
);
ground.receiveShadow = true;
scene.add(ground);
const grid = new THREE.GridHelper(3200, 32, 0xbfc3c9, 0xcdd0d6);
grid.rotation.x = Math.PI / 2;
grid.position.z = 0.5;
scene.add(grid);

/* ---------- stage (robot + lab props) + animation ---------- */
const P = JSON.parse(JSON.stringify(defaultParams));
const ui = { animate: true, turntable: false };
let stage = null, robot = null, mixer = null, action = null;

function rebuild() {
  if (stage) { scene.remove(stage); disposeRobot(stage); }
  robot = buildRobot(P);
  const setup = setupPipettingStage(robot, { ...defaultParams, ...P });
  stage = setup.stage;
  scene.add(stage);
  mixer = new THREE.AnimationMixer(stage);
  action = mixer.clipAction(setup.clip);
  action.play();
  if (freezeT !== null) { mixer.setTime(freezeT); ui.animate = false; }
  const dof = countDOF(robot);
  document.getElementById('hud').innerHTML =
    `Arm <b>7 DOF</b> · Hand <b>${dof - 7} DOF</b> · <b>${dof} joints</b> — ` +
    `animation: <b>pipetting</b> (${setup.clip.duration}s loop) · parametric, mm`;
}
rebuild();

const gui = new GUI({ title: 'Parameters' });
const arm = gui.addFolder('Arm');
arm.add(P, 'link1_len', 260, 450, 1).name('upper arm length');
arm.add(P, 'link2_len', 220, 400, 1).name('forearm length');
arm.add(P, 'elbow_offset', 0, 120, 1).name('elbow offset');
arm.add(P, 'seam_groove_width', 0.5, 4, 0.1).name('seam groove');
const hand = gui.addFolder('Hand');
hand.add(P, 'palm_len', 70, 130, 1).name('palm length');
hand.add(P, 'finger_spacing', 16, 30, 0.5).name('finger spacing');
hand.add(P.finger_scales, 'index', 0.6, 1.2, 0.01);
hand.add(P.finger_scales, 'middle', 0.6, 1.2, 0.01);
hand.add(P.finger_scales, 'ring', 0.6, 1.2, 0.01);
hand.add(P.finger_scales, 'little', 0.6, 1.2, 0.01);
hand.close();
gui.add(P, 'brand_text').name('engraving');
gui.add(ui, 'animate').name('play animation');
gui.add(ui, 'turntable');
gui.onFinishChange(rebuild);
if (isShot) gui.close();

/* ---------- downloads ---------- */
function saveBlob(blob, name) {
  const a = document.createElement('a');
  a.href = URL.createObjectURL(blob);
  a.download = name;
  a.click();
  setTimeout(() => URL.revokeObjectURL(a.href), 5000);
}

/* glTF is Y-up + meters: build a fresh stage, wrap, export */
function exportGLB(withAnimation) {
  const r = buildRobot(P);
  let exportRoot, animations = [];
  if (withAnimation) {
    const s = setupPipettingStage(r, { ...defaultParams, ...P });
    exportRoot = s.stage;
    animations = [s.clip];
  } else {
    exportRoot = r;
  }
  exportRoot.rotation.set(-Math.PI / 2, 0, 0);
  exportRoot.scale.setScalar(0.001);
  const wrap = new THREE.Group();
  wrap.add(exportRoot);
  wrap.updateMatrixWorld(true);
  new GLTFExporter().parse(
    wrap,
    (buf) => saveBlob(new Blob([buf], { type: 'model/gltf-binary' }),
      withAnimation ? 'robios-pipetting.glb' : 'robios-arm.glb'),
    (err) => alert('Export failed: ' + err),
    { binary: true, animations },
  );
}

document.getElementById('dl-anim').onclick = () => exportGLB(true);
document.getElementById('dl-static').onclick = () => exportGLB(false);
for (const [id, file] of [['dl-robot', 'robot.js'], ['dl-animjs', 'anim.js']]) {
  document.getElementById(id).onclick = async () => {
    const src = await (await fetch('./' + file)).text();
    saveBlob(new Blob([src], { type: 'text/javascript' }), file);
  };
}

/* ---------- loop ---------- */
const clock = new THREE.Clock();
renderer.setAnimationLoop(() => {
  const dt = clock.getDelta();
  if (ui.animate && mixer) mixer.update(dt);
  if (ui.turntable && stage) stage.rotation.z += dt * 0.3;
  controls.update();
  renderer.render(scene, camera);
});

addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
