{"content":"// Bakes the portable GLB files (glTF conventions: Y-up, meters):
//   robios-pipetting.glb — robot + lab props + "pipetting" animation clip
//   robios-arm.glb       — static robot only (open hand, no props)
// Usage: node bake_glb.mjs
import * as THREE from 'three';
import { readFile, writeFile } from 'node:fs/promises';

// minimal FileReader shim for GLTFExporter under Node
globalThis.FileReader = class {
  readAsArrayBuffer(blob) {
    blob.arrayBuffer().then((buf) => { this.result = buf; this.onloadend?.(); });
  }
  readAsDataURL(blob) {
    blob.arrayBuffer().then((buf) => {
      this.result = 'data:«HIGH_ENTROPY»;base64,' + Buffer.from(buf).toString('base64');
      this.onloadend?.();
    });
  }
};

const { GLTFExporter } = await import('«HIGH_ENTROPY».js');
const { buildRobot, defaultParams, setBrandFont } = await import('./robot.js');
const { setupPipettingStage } = await import('./anim.js');

const fontJson = JSON.parse(await readFile(
  new URL('.«HIGH_ENTROPY».typeface.json', import.meta.url), 'utf8'));
setBrandFont(fontJson);

function exportGLB(root, animations, outfile) {
  return new Promise((resolve, reject) => {
    root.rotation.set(-Math.PI / 2, 0, 0); // Z-up -> Y-up
    root.scale.setScalar(0.001);           // mm -> m
    const wrap = new THREE.Group();
    wrap.add(root);
    wrap.updateMatrixWorld(true);
    new GLTFExporter().parse(
      wrap,
      async (buf) => {
        await writeFile(outfile, Buffer.from(buf));
        console.log('wrote', outfile, '-', (buf.byteLength / 1e6).toFixed(2), 'MB');
        resolve();
      },
      reject,
      { binary: true, animations },
    );
  });
}

const p = { ...defaultParams };

// animated stage
const robot = buildRobot(p);
const { stage, clip } = setupPipettingStage(robot, p);
await exportGLB(stage, [clip], 'robios-pipetting.glb');

// static arm
await exportGLB(buildRobot(p), [], 'robios-arm.glb');
