<html lang="en">
<head>
<meta charset="utf-8" />
<meta name="viewport" content="width=device-width, initial-scale=1" />
<title>ROBIOS embed example</title>
<style>
  body { margin: 0; font-family: ui-sans-serif, sans-serif; background: #0d1017; color: #e8eaf0; }
  .hero { max-width: 1100px; margin: 0 auto; padding: 48px 24px; }
