<script type="module">
import * as THREE from 'three';
import { OrbitControls } from '«HIGH_ENTROPY».js';
import { RoomEnvironment } from '«HIGH_ENTROPY».js';
import { buildRobot, defaultParams, setBrandFont } from './robot.js';
import { setupPipettingStage } from './anim.js';

const el = document.getElementById('robot-3d');

// font for the white ROBIOS engraving
setBrandFont(await (await fetch(
  'https://cdn.jsdelivr.net/npm/three@0.169.«HIGH_ENTROPY».typeface.json')).json());

const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.setSize(el.clientWidth, el.clientHeight);
renderer.shadowMap.enabled = true;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
el.appendChild(renderer.domElement);

const scene = new THREE.Scene();
scene.background = new THREE.Color(0x12151d);     // or null for transparent
const pmrem = new THREE.PMREMGenerator(renderer);
scene.environment = pmrem.fromScene(new RoomEnvironment(), 0.04).texture;
scene.environmentIntensity = 0.8;

const camera = new THREE.PerspectiveCamera(38, el.clientWidth / el.clientHeight, 1, 20000);
camera.up.set(0, 0, 1);                            // model is Z-up
camera.position.set(1620, -1420, 980);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(220, 0, 480);
controls.enableDamping = true;
controls.enableZoom = false;                       // don't steal page scroll

const sun = new THREE.DirectionalLight(0xffffff, 1.8);
sun.position.set(700, -500, 1400);
sun.castShadow = true;
sun.shadow.mapSize.set(1024, 1024);
sun.shadow.camera.left = sun.shadow.camera.bottom = -1200;
sun.shadow.camera.right = sun.shadow.camera.top = 1200;
sun.shadow.camera.far = 5000;
scene.add(sun, new THREE.HemisphereLight(0x99a7bb, 0x30343c, 0.6));

// robot + lab props + pipetting animation
const robot = buildRobot();                        // pass { link1_len: 380, ... } to customize
const { stage, clip } = setupPipettingStage(robot, defaultParams);
scene.add(stage);
const mixer = new THREE.AnimationMixer(stage);
mixer.clipAction(clip).play();

const clock = new THREE.Clock();
renderer.setAnimationLoop(() => {
  mixer.update(clock.getDelta());
  controls.update();
  renderer.render(scene, camera);
